INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e3a4c893-c51a-4a39-8d97-f7a9487364c2',
  '00000000-0000-0000-0000-000000000001',
  $escape$Matplotlib — Visualizing Feature Engineering Transforms Side by Side$escape$,
  $escape$Feature engineering transforms are only as good as your ability to inspect them. Matplotlib's subplot grid makes it trivial to compare raw vs. engineered features in a single figure. Use `fig, axes = plt.subplots(1, 3)` to lay out before-and-after histograms for scaling, binning, and encoded categoricals. For one-hot encoded columns, `axes[0].bar()` with category counts beats a histogram. For min-max scaled numerics, overlay the original distribution against the scaled one on `axes[1]` using twin y-axes via `axes[1].twinx()`. For binned features, `axes[2].hist()` with the `bins` parameter matching your `pd.cut()` edges ensures the visual aligns with your actual bin boundaries. Color-code transforms consistently — raw in `#1f77b4`, engineered in `#ff7f0e` — and call `ax.set_title()` per panel so each transform is instantly identifiable. Adding `ax.axvline()` at bin edges or scaling bounds gives immediate visual validation that your pipeline isn't clipping or collapsing variance.$escape$,
  $escape$import matplotlib.pyplot as plt
import numpy as np

np.random.seed(42)
raw = np.random.exponential(scale=2.0, size=500)
scaled = (raw - raw.min()) / (raw.max() - raw.min())
bins_edges = [0, 1, 3, 6, raw.max()]

fig, axes = plt.subplots(1, 3, figsize=(14, 4))
axes[0].hist(raw, bins=30, color='#1f77b4', edgecolor='black')
axes[0].set_title('Raw Distribution')
axes[1].hist(scaled, bins=30, color='#ff7f0e', edgecolor='black')
axes[1].set_title('Min-Max Scaled')
axes[2].hist(raw, bins=bins_edges, color='#2ca02c', edgecolor='black')
for edge in bins_edges:
    axes[2].axvline(edge, color='red', linestyle='--', linewidth=0.8)
axes[2].set_title('Custom Binned')
plt.tight_layout()
plt.show()$escape$,
  $escape$python$escape$,
