INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f031cdbe-41cf-4b48-9714-6533537b4374',
  '00000000-0000-0000-0000-000000000001',
  $escape$Matplotlib Time Series — Resampling, Rolling Windows, and Seasonality in One Plot$escape$,
  $escape$Matplotlib pairs naturally with pandas for time series visualization, but the key is layering resampled data, rolling statistics, and seasonal patterns into a single readable figure. Use `ax.plot()` on a DatetimeIndex-based Series for automatic tick formatting via `mdates`. Plot raw data with low alpha, overlay a rolling mean using `Series.rolling().mean()`, and add resampled aggregates as a stem or bar plot on a twin axis. For seasonality, `ax.axvspan()` highlights recurring intervals — weekends, quarters, fiscal years. Control date tick density with `mdates.MonthLocator()` and `mdates.DateFormatter('%b %Y')` to prevent label overlap. Use `ax.fill_between()` to shade rolling standard deviation bands around the mean. For lag feature inspection, `ax.acorr()` plots autocorrelation directly — faster than building it manually. Set `maxlags` to limit computation. Combine all layers in subplots via `fig, axes = plt.subplots(3, 1, sharex=True)` so zooming propagates across panels.$escape$,
  $escape$import matplotlib.pyplot as plt
import matplotlib.dates as mdates
import pandas as pd
import numpy as np

dates = pd.date_range('2023-01-01', periods=365, freq='D')
ts = pd.Series(np.cumsum(np.random.randn(365)) + np.sin(np.arange(365)*2*np.pi/30)*5, index=dates)

fig, axes = plt.subplots(3, 1, sharex=True, figsize=(12, 8))
axes[0].plot(ts, alpha=0.4, label='Raw')
axes[0].plot(ts.rolling(30).mean(), lw=2, label='30d MA')
axes[0].fill_between(ts.index, ts.rolling(30).mean()-ts.rolling(30).std(), ts.rolling(30).mean()+ts.rolling(30).std(), alpha=0.15)
axes[0].legend(); axes[0].set_title('Rolling Window')
axes[1].bar(ts.resample('ME').mean().index, ts.resample('ME').mean(), width=20, label='Monthly Mean')
axes[1].legend(); axes[1].set_title('Resampled')
axes[2].acorr(ts.values, maxlags=60, usevlines=True, lw=0.5)
axes[2].set_title('Autocorrelation (Lag Features)')
axes[2].xaxis.set_major_formatter(mdates.DateFormatter('%b %Y'))
plt.tight_layout(); plt.show()$escape$,
  $escape$python$escape$,
