INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '260a6e7b-1cdd-4d21-adf1-289d7b1f9f20',
  '00000000-0000-0000-0000-000000000001',
  $escape$matplotlib — Embedding Dataset Version Provenance Directly into Your Figures$escape$,
  $escape$Matplotlib figures are portable artifacts — and `savefig(metadata={...})` lets them carry dataset provenance without a sidecar file. For PNG outputs, matplotlib writes arbitrary key-value pairs into iTXt chunks; for PDF, into XMP document info. Inject your DVC commit hash, S3 dataset URI, or LakeFS branch directly at save time, making the plot the canonical record of which data produced which curve.

For visual comparison across versions, overlay per-version learning curves on a single `Axes`. Use distinct `linestyle` values and version-tagged `label=` strings. Call `ax.axvline()` at the epoch boundary where a dataset was upgraded — this marks mid-run dataset transitions that would otherwise be invisible in a smoothed loss curve.

To automate provenance injection, shell out to `dvc params diff --show-md5` via `subprocess.check_output` and insert the result into the metadata dict before calling `savefig`. Later, verify embedded provenance with `PIL.Image.open('plot.png').text` — no log file required. This pattern turns every exported matplotlib figure into a queryable experiment record.$escape$,
  $escape$import matplotlib.pyplot as plt
import matplotlib
import numpy as np

epochs = np.arange(1, 21)
v1_loss = 0.8 * np.exp(-0.15 * epochs) + 0.05
v2_loss = 0.7 * np.exp(-0.18 * epochs) + 0.03

fig, ax = plt.subplots(figsize=(8, 4))
ax.plot(epochs, v1_loss, label="dataset v1.2.0", linestyle="--", color="steelblue")
ax.plot(epochs, v2_loss, label="dataset v2.0.0", linestyle="-", color="tomato")
ax.axvline(x=10, color="gray", linestyle=":", label="dataset upgrade")
ax.set(xlabel="Epoch", ylabel="Val Loss", title="Val Loss by Dataset Version")
ax.legend()

fig.savefig(
    "training_curves.png",
    metadata={
        "dataset_v1_sha": "sha256:a3f9c1",
        "dataset_v2_sha": "sha256:b7c2e4",
        "model": "resnet50",
        "Software": f"matplotlib {matplotlib.__version__}",
    },
)$escape$,
  $escape$python$escape$,
